async (params, browser) => {
  // Open Facebook group
  await browser.open(`${params.group_url}`)

  // Wait for group page to load
  await browser.waitForSelector('[role=\'main\'], [role=\'feed\'], h1', 15000)

  // Let group page render
  await browser.wait(3000)

  // Scroll to load group info
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(2000)

  // Scroll to load group posts
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll further for more posts
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

